// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <string.h>

typedef struct {int end; char col;} Op;

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, K; scanf("%d %d", &N, &K);
        char c[20005]; scanf("%s", c);
        Op stack[20005];
        int top = -1; // empty stack
        int ans = 0;
        int impossible = 0;
        for (int i = 0; i < N && !impossible; ++i) {
            // remove operations that ended before i
            while (top >= 0 && stack[top].end == i) top--;
            char cur = (top >= 0) ? stack[top].col : 0;
            if (cur != c[i]) {
                if (i + K > N) { impossible = 1; break; }
                // start new operation
                ++ans;
                ++top;
                stack[top].end = i + K; // first index not covered
                stack[top].col = c[i];
                cur = c[i];
            }
        }
        if (impossible) printf("-1\n");
        else printf("%d\n", ans);
    }
    return 0;
}

