// COMPLETE, COMPILABLE Java code
import java.io.*;
import java.util.*;
public class Main {
    private static class Op {int end; char col; Op(int e, char c){end=e; col=c;}}
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int K = Integer.parseInt(st.nextToken());
            String c = br.readLine().trim();
            Deque<Op> stack = new ArrayDeque<>();
            int ans = 0;
            boolean impossible = false;
            for (int i = 0; i < N && !impossible; i++) {
                while (!stack.isEmpty() && stack.peekLast().end == i) stack.pollLast();
                char cur = stack.isEmpty() ? 0 : stack.peekLast().col;
                if (cur != c.charAt(i)) {
                    if (i + K > N) { impossible = true; break; }
                    ans++;
                    stack.addLast(new Op(i + K, c.charAt(i)));
                }
            }
            out.append(impossible ? -1 : ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

