const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const K = Number(input[idx++]);
  const c = input[idx++];
  const stack = []; // each element: [end, colour]
  let ans = 0;
  let impossible = false;
  for (let i = 0; i < N; ++i) {
    while (stack.length && stack[stack.length - 1][0] === i) stack.pop();
    const cur = stack.length ? stack[stack.length - 1][1] : null;
    if (cur !== c[i]) {
      if (i + K > N) { impossible = true; break; }
      ans++;
      stack.push([i + K, c[i]]);
    }
  }
  outputs.push(impossible ? '-1' : String(ans));
}
